  // (icmp eq/ne (and (add A, -1), ~P2), 0)
  //    -> (icmp ne/eq (and A, P2-1), 0)
  // iff P2 is a power of 2
  // The logic is: (A - 1) & ~P2 == 0 means bits set in (A-1) are subset of {bit set in P2}
  // Since A-1 flips bit 0, the result is 0 iff bit 0 is cleared in ~P2 i.e., P2>1
  // Actually, ((A-1) & ~P2) == 0 iff ((A-1) & ~P2) has no bits set
  // This is equivalent to checking A against specific bit patterns.
  // For range-constrained values, this simplifies to checking low bits.
  // (A-1) & ~P2 == 0 iff A & (P2-1) == P2-1 for values where overflow doesn't affect result
  // When C==0 and Addend==-1: (A-1) & Mask == 0 becomes ~(A-1) | ~Mask == ~0 i.e., (A-1)|~Mask == -1
  {
    Value *A;
    const APInt *Mask;
    if (C.isZero() &&
        match(And, m_And(m_OneUse(m_Add(m_Value(A), m_AllOnes())),
                         m_APInt(Mask)))) {
      // If Mask is of the form ~C2 where C2 is power of 2, i.e., exactly one 0 bit
      if (Mask->isNegatedPowerOf2()) {
        // ~Mask is the bit position that must be checked
        APInt LowBits = ~(*Mask);
        // (icmp eq (and (add A, -1), ~LowBits), 0) -> (icmp ne (and A, LowBits), 0)
        // (icmp ne (and (add A, -1), ~LowBits), 0) -> (icmp eq (and A, LowBits), 0)
        Value *NewAnd = Builder.CreateAnd(A, ConstantInt::get(A->getType(), LowBits));
        auto NewPred = Pred == CmpInst::ICMP_EQ ? CmpInst::ICMP_NE : CmpInst::ICMP_EQ;
        return new ICmpInst(NewPred, NewAnd, Constant::getNullValue(NewAnd->getType()));
      }
    }
  }

